$logs          = array_filter(
                    $output->items,
                    function ( $log ) use ( $global_ids, $is_global ) {
                        $temp_job = (bool) \BackWPup_Option::get( $log['jobid'], 'tempjob', false );
                        if ( $temp_job ) {
                            return false;
                        }
                        if ( 0 === $is_global ) {
                            return in_array( intval( $log['jobid'] ), $global_ids, true );
                        }
                        return ! empty( $log['jobid'] );
                    }
                )

